openai_response_format:
from openai import OpenAI

client = OpenAI()
response = client.chat.completions.create(
    model="gpt-4o",
    messages=[{"role": "user", "content": prompt}],
    response_format={
        "type": "json_schema",
        "json_schema": {
            "name": "answer_with_confidence",
            "strict": True,
            "schema": {
                "type": "object",
                "properties": {
                    "answer": {"type": "string"},
                    "confidence": {"type": "number"},
                    "reasoning": {"type": "string"}
                },
                "required": ["answer", "confidence"],
                "additionalProperties": False
            }
        }
    }
)
result = json.loads(response.choices[0].message.content)

anthropic_tool_use_como_structured_outpu:
import anthropic

client = anthropic.Anthropic()
response = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=1024,
    tools=[{
        "name": "structured_answer",
        "description": "Provide a structured answer with confidence score",
        "input_schema": {
            "type": "object",
            "properties": {
                "answer": {"type": "string", "description": "Resposta principal"},
                "confidence": {"type": "number", "minimum": 0.0, "maximum": 1.0},
                "reasoning": {"type": "string"}
            },
            "required": ["answer", "confidence"]
        }
    }],
    tool_choice={"type": "tool", "name": "structured_answer"},
    messages=[{"role": "user", "content": prompt}]
)
result = response.content[0].input  # dict com answer + confidence

google_gemini_responseschema:
import google.generativeai as genai

model = genai.GenerativeModel(
    "gemini-2.0-flash",
    generation_config=genai.GenerationConfig(
        response_mime_type="application/json",
        response_schema={
            "type": "object",
            "properties": {
                "answer": {"type": "string"},
                "confidence": {"type": "number"},
                "reasoning": {"type": "string"}
            },
            "required": ["answer", "confidence"]
        }
    )
)
response = model.generate_content(prompt)
result = json.loads(response.text)
